  ('elementary-0a2fc18c-moex-00776', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '經常帳餘額波動的主要來源為何？', '["淨利息收入", "淨移轉", "淨出口", "淨稅收"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00777', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '若Ａ國在某年度的國際收支帳為：商品及服務出口200億美元、利息所得收入20億美元、外國投資為120 億美元、商品及服務進口190億美元、利息所得支出25億美元、淨片面移轉支出負10億美元、對國外 投資為130億美元，以及官方外匯存底減少15億美元。Ａ國該年度的國際收支為：', '["逆差15億美元", "順差15億美元", "平衡，是0億美元", "順差5億美元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00778', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '美元相對英鎊升值時，下列敘述何者正確？', '["美國牛仔褲出口至倫敦增加", "蘇格蘭毛衣出口至紐約增加", "美國官方經常帳結算餘額上升", "美國通貨膨脹率相對於英國通貨膨脹率高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00779', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '當勞工對一般物價水準沒有完整的資訊時，依據總合供給與總合需求模型，中央銀行若採行未預料到的 （unanticipated）寬鬆貨幣政策，則下列敘述何者正確？', '["短期均衡下，物價變動不確定，但產出確定增加", "短期均衡下，物價水準上漲，且產出增加", "長期均衡達成時，物價漲幅和產出增幅都等於貨幣供給的增幅", "長期均衡達成時，物價漲幅等於貨幣供給的增幅，然而產出不變，並且預期物價水準不等於實際物價水準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00780', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '考慮一個簡單凱因斯模型中，假設沒有政府部門、沒有進出口且僅存在自發性投資。當均衡所得為1,000 單位時，總消費為600單位；當均衡所得為2,000單位時，總消費為1,100單位。若目前的均衡所得為3,000 單位，則下列敘述何者正確？', '["自發性消費支出為200單位", "誘發性消費為1,600單位", "自發性投資為1,400單位", "總儲蓄為1,500單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00781', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在短期內，下列何項是廠商會在價格上漲時擴大生產的原因？', '["貨幣工資保持不變下，產品的較高價格使公司擴大生產變得有利可圖", "每家公司都必須使其產量保持在其競爭對手的水平，有些公司會隨著價格上漲而擴大產量", "較高的價格使企業可以透過提供更高的工資來僱用更多的工人，從而提高生產力和利潤", "廠商可以透過增加維護機器來增加利潤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00782', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設甲公司處於均衡狀態，且其資本存量處於公司所想要的水準。現在，中央銀行降低名目利率，以致 於預期的實質利率（expectedrealinterestrate）下降，則甲公司想要的資本存量（desiredcapitalstock）會 有什麼變化及其原因為何？', '["降低；因為資本的未來邊際生產力（thefuturemarginalproductivityofcapital）降低了", "提高；因為資本的未來邊際生產力上升了", "降低；因為目前資本的使用者成本（theusercostofcapital）提高了", "提高；因為目前資本的使用者成本降低了"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
